const body = $input.first().json?.body ?? $input.first().json;
const required = ['tenantId', 'accessToken', 'instanceUrl', 'crmAuthToken', 'crmBaseUrl'];
const missing = required.filter(k => !body[k]);
if (missing.length > 0) {
  throw new Error('Missing required parameters: ' + missing.join(', '));
}
const instanceUrl = body.instanceUrl.replace(/\/+$/, '');
const crmBaseUrl = body.crmBaseUrl.replace(/\/+$/, '');
return [{
  json: {
    tenantId: body.tenantId,
    accessToken: body.accessToken,
    instanceUrl,
    crmAuthToken: body.crmAuthToken,
    crmBaseUrl,
    correlationId: require('crypto').randomUUID(),
    sfApiBase: instanceUrl + '/services/data/v59.0'
  }
}];

const params = $('01_Validate').first().json;
const pages = $('02_FetchContacts').all();
const allRecords = [];
for (const page of pages) {
  const records = page.json?.records ?? [];
  allRecords.push(...records);
}
const items = allRecords.map(c => ({
  externalId: c.Id,
  externalSource: 'salesforce',
  name: c.Name || 'Unknown',
  email: c.Email || '',
  phone: c.Phone || '',
  company: c.Account?.Name || ''
}));
return [{ json: { ...params, contactItems: items, contactCount: items.length } }];

const contactResults = $('04_UpsertContacts').first().json?.results ?? [];
const contactMap = {};
for (const r of contactResults) {
  if (r.id) contactMap[r.externalId] = r.id;
}
return [{ json: { contactMap, contactResults } }];

const params = $('01_Validate').first().json;
const pages = $('06_FetchLeads').all();
const allRecords = [];
for (const page of pages) {
  const records = page.json?.records ?? [];
  allRecords.push(...records);
}
const SF_STATUS_MAP = {
  'Open - Not Contacted': 'new',
  'Working - Contacted': 'contacted',
  'Closed - Converted': 'qualified',
  'Closed - Not Converted': 'lost'
};
const items = allRecords.map(l => ({
  externalId: l.Id,
  externalSource: 'salesforce',
  name: ((l.FirstName || '') + ' ' + (l.LastName || '')).trim() || 'Unknown',
  email: l.Email || '',
  company: l.Company || '',
  status: SF_STATUS_MAP[l.Status] || 'new'
}));
return [{ json: { ...params, leadItems: items, leadCount: items.length } }];

const params = $('01_Validate').first().json;
const pages = $('09_FetchOpportunities').all();
const allRecords = [];
for (const page of pages) {
  const records = page.json?.records ?? [];
  allRecords.push(...records);
}
const contactMap = $('05_BuildContactMap').first().json.contactMap;
const STAGE_MAP = {
  'Prospecting': 'prospecting',
  'Qualification': 'qualification',
  'Needs Analysis': 'qualification',
  'Value Proposition': 'proposal',
  'Id. Decision Makers': 'proposal',
  'Perception Analysis': 'proposal',
  'Proposal/Price Quote': 'proposal',
  'Negotiation/Review': 'negotiation',
  'Closed Won': 'won',
  'Closed Lost': 'lost'
};
const items = allRecords.map(o => {
  const ocr = o.OpportunityContactRoles?.records?.[0];
  return {
    externalId: o.Id,
    externalSource: 'salesforce',
    name: o.Name || 'Untitled',
    contactExternalId: ocr?.ContactId || '',
    value: o.Amount || 0,
    stage: STAGE_MAP[o.StageName] || 'prospecting',
    company: o.Account?.Name || ''
  };
});
return [{ json: { ...params, dealItems: items, dealCount: items.length } }];

const params = $('01_Validate').first().json;
const contactResults = $('05_BuildContactMap').first().json.contactResults;
const leadResults = $('08_UpsertLeads').first().json?.results ?? [];
const dealResults = $('11_UpsertDeals').first().json?.results ?? [];

function summarize(results) {
  const s = { created: 0, updated: 0, skipped: 0, failed: 0 };
  for (const r of results) { s[r.status] = (s[r.status] || 0) + 1; }
  return s;
}

const allResults = [...contactResults, ...leadResults, ...dealResults];
const errors = allResults
  .filter(r => r.status === 'failed')
  .map(r => ({ externalId: r.externalId, error: r.error }));

const summary = {
  contacts: summarize(contactResults),
  leads: summarize(leadResults),
  deals: summarize(dealResults)
};

return [{
  json: {
    ok: errors.length === 0,
    tenantId: params.tenantId,
    provider: 'salesforce',
    correlationId: params.correlationId,
    summary,
    errors,
    totalRecords: contactResults.length + leadResults.length + dealResults.length
  }
}];
